company name : {{ $json.companyName }}
job Description: {{ $json.descriptionText }}

options.systemMessage:
=You are an expert LinkedIn job posting filtering agent.  
Your only task is to determine whether or not the job posting provided to you is suitable for the specific candidate with the provided original resume. The original resume may include various skills or qualifications, you will have to think deeply and determine if any of the candidate’s skillsets or knowledge is suitable to the job posting.  

Here is the information from the job posting and company:  
Company Name: {{ $json.companyName }}  
Job Posting Description: {{ $json.descriptionText }}  

Here is the candidate’s original resume:  {{ $('Extract from File').item.json.text }}

If the job posting is suitable to the candidate according to their skills, experience and knowledge. You must rate whether or not the candidate’s resume is suitable to the job posting out of 100. If the rating is 0, then the output will be 0 meaning that the job posting in NOT suitable to the candidate at all. If the rating is 100, then the output will be 100 meaning that the job posting is extremely suitable to the candidate.  

Output in JSON format as indicated in the output parser.

parameters.jsCode:
// This works perfectly when placed AFTER the "Loop Over Items" node (once the loop is done)
const results = [];

for (const item of $input.all()) {
  // 1. Extract the resume HTML body
  let resumeBody = "";
  if (typeof item.json.output === "string") {
    resumeBody = item.json.output;
  } else if (item.json.output?.text) {
    resumeBody = item.json.output.text;
  } else if (item.json.text) {
    resumeBody = item.json.text;
  }

  // Clean up LLM artifacts
  resumeBody = resumeBody.replace(/```html|```/g, "").trim();

  // 2. Identify Company Name
  // We check the item's JSON first, then the output, then fallback
  let companyName = item.json.company_name || 
                    item.json.companyName || 
                    item.json.output?.company_name ||
                    "Tailored";

  // Manual overrides based on content
  if (companyName === "Tailored") {
    if (resumeBody.includes("VISEO")) companyName = "VISEO";
    else if (resumeBody.includes("L3M HOLDING")) companyName = "L3M HOLDING";
    else if (resumeBody.includes("MyUnisoft")) companyName = "MyUnisoft";
  }

  // 3. Make filename safe for OS
  const safeCompanyName = companyName.replace(/[^a-z0-9]/gi, "_").toLowerCase();
  const fileName = `Resume_REDACTED_${safeCompanyName}.html`;

  // 4. Build the final HTML with your styles
  const finalHtml = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <title>CV - REDACTED – ${companyName}</title>
  <style>
    :root { --body-padding: 1.4cm 1.2cm 1cm 1.4cm; }
    body {
      font-family: "Latin Modern Roman", "Times New Roman", serif;
      font-size: 11pt;
      line-height: 1.3;
      color: #000;
      margin: 0;
      padding: var(--body-padding);
      background: white;
    }
    .header-table { width: 100%; border-collapse: collapse; margin-bottom: 12px; }
    .header-table td { vertical-align: top; }
    .name { font-size: 22pt; font-weight: bold; margin: 0 0 2px 0; letter-spacing: 0.02em; }
    .contact-info { text-align: right; font-size: 9pt; line-height: 1.8; }
    .contact-info a { text-decoration: none; color: #000; }
    .contact-info a:hover { text-decoration: underline; }
    section { margin-top: 6px; margin-bottom: 4px; }
    h2 {
      font-size: 11pt;
      text-transform: uppercase;
      font-variant: small-caps;
      font-weight: bold;
      border-bottom: 1px solid #000;
      margin: 0 0 4px 0;
      padding-bottom: 1px;
      letter-spacing: 0.05em;
    }
    .row-spread { display: flex; justify-content: space-between; align-items: baseline; font-weight: bold; font-size: 10.5pt; }
    .sub-row { display: flex; justify-content: space-between; font-style: italic; font-size: 9.5pt; margin-bottom: 2px; }
    ul { margin: 3px 0 7px 18px; padding: 0; list-style-type: disc; }
    li { margin-bottom: 2px; text-align: justify; font-size: 10pt; }
    .skills-container { font-size: 10pt; line-height: 1.6; }
    .skills-container div { margin-bottom: 1px; }
    .bold { font-weight: bold; }
    .italic { font-style: italic; }
    .small-text { font-size: 9pt; font-weight: normal; }
    p { font-size: 10pt; margin: 0; text-align: justify; line-height: 1.4; }
  </style>
</head>
<body>
${resumeBody}
</body>
</html>`;

  // 5. Push individual result back into the n8n item array
  results.push({
    json: {
      ...item.json, // Keep original data (company name, etc.)
      html_content: finalHtml,
      dynamicFileName: fileName,
      resolvedCompanyName: companyName
    }
  });
}

return results;

